'use client';

import { SingleImageDrop } from '@/components/dropzone/single-image-drop';

interface AvatarDropzoneOutlinedProps {
    className?: string;
    onFileSelect?: (file: File | null) => void;
    maxSize?: number;
    defaultImage?: string;
}

export function AvatarDropzoneOutlined({
    className,
    onFileSelect,
    maxSize = 5 * 1024 * 1024,
    defaultImage,
}: AvatarDropzoneOutlinedProps) {
    return (
        <SingleImageDrop
            variant="outlined"
            onFile={onFileSelect || (() => {})}
            maxSize={maxSize}
            preview={defaultImage}
            showStatusBadge={true}
            showRemoveButton={true}
            className={className}
        />
    );
}
